parameters.text:
=Job posting URL:
{{ $('ScrapeJobListing').item.json.data.metadata.url }}
Validated employer:
{{ $json.output.company_name }}

Validated job title:
{{ $json.output.job_title }}

<job_posting>
{{ $('ScrapeJobListing').item.json.data.markdown }}
</job_posting>

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "status": {
      "type": "string",
      "enum": [
        "success",
        "validation_failed"
      ],
      "description": "Whether the content is a complete and usable job posting."
    },
    "company_name": {
      "type": "string",
      "description": "The employer name. Use an empty string when validation fails."
    },
    "job_title": {
      "type": "string",
      "description": "The advertised job title. Use an empty string when validation fails."
    },
    "validation_message": {
      "type": "string",
      "description": "A concise failure reason. Leave empty when validation succeeds."
    }
  },
  "required": [
    "status",
    "company_name",
    "job_title",
    "validation_message"
  ],
  "additionalProperties": false
}

